// Handles both Clio webhooks and generic matter-close payloads.
// Sets is_valid_closure = true only when the event signals a genuine matter
// closure and the client has a phone number to receive the review request.

const raw  = $input.first().json;
const body = raw.body || raw;

let normalized;

// Clio webhook shape: { topic: 'matter', payload: { status: 'Closed', client: { ... } } }
if (body.topic === 'matter' || (body.payload && body.payload.status !== undefined)) {
  const p      = body.payload || body;
  const status = (p.status || '').toLowerCase();
  const client = p.client || {};
  const phones = client.phone_numbers || [];

  normalized = {
    matter_id:    String(p.id || p.matter_id || ''),
    matter_title: p.display_number || p.description || p.name || 'Matter',
    client_name:  client.name || p.contact_name || '',
    client_phone: (phones[0] && phones[0].number) || p.client_phone || '',
    client_email: client.primary_email_address || p.client_email || '',
    closed_at:    p.closed_at || new Date().toISOString(),
    source:       'clio',
    is_valid_closure: status === 'closed'
      && !!((phones[0] && phones[0].number) || p.client_phone),
  };
} else {
  // Generic webhook
  const status    = (body.matter_status || body.status || '').toLowerCase();
  const eventType = (body.event_type   || body.event  || '').toLowerCase();

  normalized = {
    matter_id:    String(body.matter_id || body.id || ''),
    matter_title: body.matter_title || body.case_name || body.name || 'Matter',
    client_name:  body.client_name  || body.contact_name || '',
    client_phone: body.client_phone || body.phone        || '',
    client_email: body.client_email || body.email        || '',
    closed_at:    body.closed_at || new Date().toISOString(),
    source:       'generic',
    is_valid_closure: (status === 'closed' || /clos/i.test(eventType))
      && !!(body.client_phone || body.phone),
  };
}

return [{ json: { ...normalized, received_at: new Date().toISOString() } }];

// Reads firm details from n8n Variables (project → Variables tab).
// Set: FIRM_NAME, FIRM_EMAIL, FIRM_FROM_EMAIL, FIRM_TWILIO_NUMBER, FIRM_GOOGLE_REVIEW_URL, FIRM_FEEDBACK_URL
const FIRM_NAME            = $vars.FIRM_NAME;
const FIRM_EMAIL           = $vars.FIRM_EMAIL;              // firm-side notifications
const FROM_EMAIL           = $vars.FIRM_FROM_EMAIL;         // must be authorised by your SMTP account
const FIRM_TWILIO_NUMBER   = $vars.FIRM_TWILIO_NUMBER;      // your Twilio sending number (E.164)
const GOOGLE_REVIEW_URL    = $vars.FIRM_GOOGLE_REVIEW_URL;  // Google Business Profile → Get more reviews
const PRIVATE_FEEDBACK_URL = $vars.FIRM_FEEDBACK_URL;       // your internal feedback form

const item    = $input.first().json;
const now     = new Date();

// 48-hour sweet spot — client remembers the outcome but acute stress has faded.
const MS_48H  = 48 * 60 * 60 * 1000;
const send_at = new Date(now.getTime() + MS_48H).toISOString();

const firstName = (item.client_name || '').split(' ')[0] || '';
const greeting  = firstName ? `Hi ${firstName}` : 'Hi there';

const ratingSms = `${greeting}, it was our honor to serve you at ${FIRM_NAME}. How was your experience? Reply 1–5 (1 = poor, 5 = excellent). Reply STOP to opt out.`;

return [{ json: {
  ...item,
  firm_name:            FIRM_NAME,
  firm_email:           FIRM_EMAIL,
  from_email:           FROM_EMAIL,
  firm_twilio_number:   FIRM_TWILIO_NUMBER,
  google_review_url:    GOOGLE_REVIEW_URL,
  private_feedback_url: PRIVATE_FEEDBACK_URL,
  send_at,
  rating_sms:           ratingSms,
} }];

