// Reads firm details from n8n Variables (project → Variables tab) — must match Set Up Review Request (Path A).
const FIRM_NAME            = $vars.FIRM_NAME;
const FIRM_EMAIL           = $vars.FIRM_EMAIL;
const FROM_EMAIL           = $vars.FIRM_FROM_EMAIL;
const FIRM_TWILIO_NUMBER   = $vars.FIRM_TWILIO_NUMBER;
const GOOGLE_REVIEW_URL    = $vars.FIRM_GOOGLE_REVIEW_URL;
const PRIVATE_FEEDBACK_URL = $vars.FIRM_FEEDBACK_URL;

// Guard: fail loudly if variables are not set.
if (!GOOGLE_REVIEW_URL) {
  throw new Error('FIRM_GOOGLE_REVIEW_URL n8n Variable is not set. Go to project → Variables tab and add it.');
}
if (!PRIVATE_FEEDBACK_URL) {
  throw new Error('FIRM_FEEDBACK_URL n8n Variable is not set. Go to project → Variables tab and add it.');
}

// Parses the inbound Twilio SMS reply.
// Twilio POSTs form-encoded fields: From (client number), Body (reply text).
const raw  = $input.first().json;
const body = raw.body || raw;

const fromNumber = (body.From || '').trim();
const rawReply   = (body.Body || '').trim();

// Extract leading digit 1–5; tolerant of extra text like '5 great!'
const match  = rawReply.match(/^([1-5])/);
const rating = match ? parseInt(match[1]) : 0;

// Filter opt-out keywords — Twilio also handles STOP automatically
const isOptOut      = /^(STOP|UNSUBSCRIBE|CANCEL|END|QUIT)/i.test(rawReply);
const isValidRating = !isOptOut && rating >= 1 && rating <= 5;
const isHappy       = rating >= 4;

const googleSms   = `Thank you! We're so glad you had a great experience at ${FIRM_NAME}. Would you mind leaving a quick Google review? It truly helps: ${GOOGLE_REVIEW_URL}`;
const feedbackSms = `Thank you for letting us know. We take every concern seriously and want to make this right. Please share your feedback privately here: ${PRIVATE_FEEDBACK_URL}`;

return [{ json: {
  from_number:          fromNumber,
  raw_reply:            rawReply,
  rating,
  is_happy:             isHappy,
  is_valid_rating:      isValidRating,
  firm_name:            FIRM_NAME,
  firm_email:           FIRM_EMAIL,
  from_email:           FROM_EMAIL,
  firm_twilio_number:   FIRM_TWILIO_NUMBER,
  google_review_url:    GOOGLE_REVIEW_URL,
  private_feedback_url: PRIVATE_FEEDBACK_URL,
  google_sms:           googleSms,
  feedback_sms:         feedbackSms,
  received_at:          new Date().toISOString(),
} }];

